#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#define SIZE 9

// Function to check if a move is valid
int isValidMove(int board[SIZE][SIZE], int x, int y, int player) {
    // Check if the cell is empty
    if (board[x][y] != 0) return 0;
    // Check if the move is within the board
    if (x < 0 || x >= SIZE || y < 0 || y >= SIZE) return 0;
    return 1;
}

// Function to update the board after a move
void updateBoard(int board[SIZE][SIZE], int x, int y, int player) {
    board[x][y] = player;
}

// Function to check for dead connected components
void checkDeadComponents(int board[SIZE][SIZE], int player) {
    // Iterate over the board to find connected components
    for (int i = 0; i < SIZE; i++) {
        for (int j = 0; j < SIZE; j++) {
            if (board[i][j] == player) {
                // Check if the component is dead
                if (isDeadComponent(board, i, j, player)) {
                    // Remove the dead component
                    removeComponent(board, i, j, player);
                }
            }
        }
    }
}

// Function to simulate the game
void simulateGame(int N) {
    int board[SIZE][SIZE] = {{0}};
    int player = 1;
    srand(time(NULL));
    for (int i = 0; i < N; i++) {
        // Generate a random valid move
        int x, y;
        do {
            x = rand() % SIZE;
            y = rand() % SIZE;
        } while (!isValidMove(board, x, y, player));
        // Update the board
        updateBoard(board, x, y, player);
        // Check for dead connected components
        checkDeadComponents(board, player);
        // Switch player
        player = (player == 1) ? 2 : 1;
        // Print the move
        printf("%d %d\n", x + 1, y + 1);
    }
}

int main() {
    int N;
    scanf("%d", &N);
    simulateGame(N);
    return 0;
}

