        // Check if the cell is empty
        if (board[x][y] != 0) return false;
        // Check if the move is within the board
        if (x < 0 || x >= SIZE || y < 0 || y >= SIZE) return false;
        return true;
    }

    // Function to update the board after a move
    public static void updateBoard(int[][] board, int x, int y, int player) {
        board[x][y] = player;
    }

    // Function to check for dead connected components
    public static void checkDeadComponents(int[][] board, int player) {
        // Iterate over the board to find connected components
        for (int i = 0; i < SIZE; i++) {
            for (int j = 0; j < SIZE; j++) {
                if (board[i][j] == player) {
                    // Check if the component is dead
                    if (isDeadComponent(board, i, j, player)) {
                        // Remove the dead component
                        removeComponent(board, i, j, player);
                    }
                }
            }
        }
    }

    // Function to simulate the game
    public static void simulateGame(int N) {
        int[][] board = new int[SIZE][SIZE];
        int player = 1;
        Random rand = new Random();
        for (int i = 0; i < N; i++) {
            // Generate a random valid move
            int x, y;
            do {
                x = rand.nextInt(SIZE);
                y = rand.nextInt(SIZE);
            } while (!isValidMove(board, x, y, player));
            // Update the board
            updateBoard(board, x, y, player);
            // Check for dead connected components
            checkDeadComponents(board, player);
            // Switch player
            player = (player == 1) ? 2 : 1;
            // Print the move
            System.out.println((x + 1) + " " + (y + 1));
        }
